/**
 * Persistence layer for the mt-cli sync mapping.
 *
 * The mapping lives at `.gsd/mt-sync.json` and tracks which GSD
 * entities (milestones, slices, tasks) have been synced to the
 * Milestone Tracker via mt-cli, along with sync timestamps and status.
 *
 * Architecture follows the github-sync extension pattern.
 */
import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";
import { atomicWriteSync } from "../gsd/atomic-write.js";

const MAPPING_FILENAME = "mt-sync.json";

function mappingPath(basePath) {
  return join(basePath, ".gsd", MAPPING_FILENAME);
}

// ─── Load / Save ────────────────────────────────────────────────────────────

/**
 * Load the sync mapping from disk.
 * Returns null if the file doesn't exist, is corrupt, or has the wrong version.
 */
export function loadSyncMapping(basePath) {
  const path = mappingPath(basePath);
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, "utf-8");
    const parsed = JSON.parse(raw);
    if (parsed?.version !== 1) return null;
    return parsed;
  } catch {
    return null;
  }
}

/**
 * Save the sync mapping to disk atomically.
 */
export function saveSyncMapping(basePath, mapping) {
  const path = mappingPath(basePath);
  atomicWriteSync(path, JSON.stringify(mapping, null, 2) + "\n");
}

/**
 * Create an empty sync mapping for a given milestone ID.
 */
export function createEmptyMapping(milestoneId) {
  return {
    version: 1,
    milestoneId,
    slices: {},
    tasks: {},
  };
}

// ─── Accessors ──────────────────────────────────────────────────────────────

/**
 * Get the record for a slice, or null if not synced.
 */
export function getSliceRecord(mapping, mid, sid) {
  return mapping.slices[`${mid}/${sid}`] ?? null;
}

/**
 * Get the record for a task, or null if not synced.
 */
export function getTaskRecord(mapping, mid, sid, tid) {
  return mapping.tasks[`${mid}/${sid}/${tid}`] ?? null;
}

/**
 * Get the mt-cli task ID for a GSD task, or null if not mapped.
 */
export function getMtTaskId(mapping, mid, sid, tid) {
  const record = getTaskRecord(mapping, mid, sid, tid);
  return record?.mtTaskId ?? null;
}

// ─── Mutators ───────────────────────────────────────────────────────────────

/**
 * Set (create or update) the record for a slice.
 */
export function setSliceRecord(mapping, mid, sid, record) {
  mapping.slices[`${mid}/${sid}`] = record;
}

/**
 * Set (create or update) the record for a task.
 */
export function setTaskRecord(mapping, mid, sid, tid, record) {
  mapping.tasks[`${mid}/${sid}/${tid}`] = record;
}

/**
 * Thin wrapper around the `mt-cli` CLI binary.
 *
 * Every public function returns `MtResult<T>` — never throws.
 * Uses `execFileSync` (not `execSync`) for safety.
 *
 * Architecture follows the github-sync/cli.js pattern.
 */
import { execFileSync } from "node:child_process";

// ─── Result Type ────────────────────────────────────────────────────────────

function ok(data) {
  return { ok: true, data };
}

function fail(error) {
  return { ok: false, error };
}

// ─── mt-cli Availability ────────────────────────────────────────────────────

let _mtCliAvailable = null;

/**
 * Check whether the `mt-cli` binary is available on PATH.
 * Result is cached for the lifetime of the process.
 */
export function mtCliIsAvailable() {
  if (_mtCliAvailable !== null) return _mtCliAvailable;
  try {
    execFileSync("mt-cli", ["--version"], {
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "ignore"],
      timeout: 5_000,
    });
    _mtCliAvailable = true;
  } catch {
    _mtCliAvailable = false;
  }
  return _mtCliAvailable;
}

/** Reset cached availability (for testing). */
export function _resetMtCliCache() {
  _mtCliAvailable = null;
}

// ─── Helpers ────────────────────────────────────────────────────────────────

const MT_CLI_TIMEOUT = 30_000;

/**
 * Run an mt-cli command and return the raw stdout as a string.
 * Returns `MtResult<string>` — never throws.
 */
function runMtCli(args, cwd) {
  try {
    const stdout = execFileSync("mt-cli", args, {
      cwd,
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "pipe"],
      timeout: MT_CLI_TIMEOUT,
    }).trim();
    return ok(stdout);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return fail(msg);
  }
}

/**
 * Run an mt-cli command with `--json` and parse the output.
 * Returns `MtResult<object>` — never throws.
 */
function runMtCliJson(args, cwd) {
  const result = runMtCli([...args, "--json"], cwd);
  if (!result.ok) return fail(result.error);
  try {
    return ok(JSON.parse(result.data));
  } catch {
    return fail(`Failed to parse JSON from mt-cli: ${result.data.slice(0, 200)}`);
  }
}

// ─── Status / Bootstrap ─────────────────────────────────────────────────────

/**
 * Check mt-cli server connectivity and config.
 * Returns `MtResult<object>` with serverUrl, milestoneId, connected, etc.
 */
export function mtCliStatus(cwd) {
  return runMtCliJson(["status"], cwd);
}

/**
 * List tasks from the Milestone Tracker.
 * Returns `MtResult<object[]>` with task records.
 */
export function mtCliTasksList(cwd, opts = {}) {
  const args = ["tasks", "list"];
  if (opts.status) {
    args.push("--status", opts.status);
  }
  return runMtCliJson(args, cwd);
}

// ─── Task Lifecycle Commands ────────────────────────────────────────────────

/**
 * Claim a task for an agent.
 * @param {string} cwd - Working directory
 * @param {string} taskId - mt-cli task ID (short or full)
 * @param {object} opts - { agent?: string }
 * @returns {MtResult<object>} - Claimed task record
 */
export function mtCliTasksClaim(cwd, taskId, opts = {}) {
  const args = ["tasks", "claim", taskId];
  if (opts.agent) {
    args.push("--agent", opts.agent);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Update task progress.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { subTotal?, subDone?, message? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksProgress(cwd, taskId, opts = {}) {
  const args = ["tasks", "progress", taskId];
  if (opts.subTotal !== undefined) {
    args.push("--sub-total", String(opts.subTotal));
  }
  if (opts.subDone !== undefined) {
    args.push("--sub-done", String(opts.subDone));
  }
  if (opts.message) {
    args.push("--message", opts.message);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Block a task with a reason.
 * @param {string} cwd
 * @param {string} taskId
 * @param {string} reason - Required block reason
 * @returns {MtResult<object>}
 */
export function mtCliTasksBlock(cwd, taskId, reason) {
  const args = ["tasks", "block", taskId, "--reason", reason];
  return runMtCliJson(args, cwd);
}

/**
 * Unblock a task with an optional message.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { message? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksUnblock(cwd, taskId, opts = {}) {
  const args = ["tasks", "unblock", taskId];
  if (opts.message) {
    args.push("--message", opts.message);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Complete a task with optional evidence.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { message?, evidence?, filesTouched? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksComplete(cwd, taskId, opts = {}) {
  const args = ["tasks", "complete", taskId];
  if (opts.message) {
    args.push("--message", opts.message);
  }
  if (opts.evidence) {
    args.push("--evidence", JSON.stringify(opts.evidence));
  }
  if (opts.filesTouched) {
    args.push("--files-touched", JSON.stringify(opts.filesTouched));
  }
  return runMtCliJson(args, cwd);
}

/**
 * Unit tests for mt-cli extension mapping.js
 *
 * Tests createEmptyMapping, load/save round-trip, accessors, and mutators.
 * Uses inline fixtures and temp directories — never touches .gsd/ on disk.
 */
import { writeFileSync, mkdirSync, rmSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import {
  createEmptyMapping,
  loadSyncMapping,
  saveSyncMapping,
  getSliceRecord,
  getTaskRecord,
  getMtTaskId,
  setSliceRecord,
  setTaskRecord,
} from "../mapping.js";

// ─── Helpers ────────────────────────────────────────────────────────────────

let _tmpDir;
function tmpPath() {
  if (!_tmpDir) {
    _tmpDir = join(tmpdir(), `mt-sync-test-${Date.now()}`);
    mkdirSync(_tmpDir, { recursive: true });
  }
  return _tmpDir;
}

function cleanup() {
  if (_tmpDir) {
    rmSync(_tmpDir, { recursive: true, force: true });
    _tmpDir = null;
  }
}

// ─── Tests ──────────────────────────────────────────────────────────────────

function assert(condition, message) {
  if (!condition) throw new Error(`Assertion failed: ${message}`);
}

function assertEqual(actual, expected, label) {
  if (actual !== expected) {
    throw new Error(`${label}: expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
  }
}

// createEmptyMapping
{
  const mapping = createEmptyMapping("M003");
  assert(mapping.version === 1, "version should be 1");
  assertEqual(mapping.milestoneId, "M003", "milestoneId");
  assert(Object.keys(mapping.slices).length === 0, "slices should be empty");
  assert(Object.keys(mapping.tasks).length === 0, "tasks should be empty");
  console.log("✓ createEmptyMapping: creates valid empty mapping");
}

// loadSyncMapping — no file
{
  const result = loadSyncMapping(tmpPath());
  assertEqual(result, null, "loadSyncMapping missing file");
  console.log("✓ loadSyncMapping: returns null when file missing");
}

// loadSyncMapping — corrupt file
{
  const dir = join(tmpPath(), "corrupt");
  mkdirSync(join(dir, ".gsd"), { recursive: true });
  writeFileSync(join(dir, ".gsd", "mt-sync.json"), "not json {{{");
  const result = loadSyncMapping(dir);
  assertEqual(result, null, "loadSyncMapping corrupt file");
  console.log("✓ loadSyncMapping: returns null for corrupt file");
}

// loadSyncMapping — wrong version
{
  const dir = join(tmpPath(), "wrongver");
  mkdirSync(join(dir, ".gsd"), { recursive: true });
  writeFileSync(join(dir, ".gsd", "mt-sync.json"), JSON.stringify({ version: 2 }));
  const result = loadSyncMapping(dir);
  assertEqual(result, null, "loadSyncMapping wrong version");
  console.log("✓ loadSyncMapping: returns null for wrong version");
}

// save + load round-trip
{
  const dir = join(tmpPath(), "roundtrip");
  mkdirSync(join(dir, ".gsd"), { recursive: true });
  const mapping = createEmptyMapping("M005");
  mapping.tasks["M005/S01/T01"] = {
    mtTaskId: "task-abc123",
    status: "in-progress",
    lastSyncedAt: "2025-01-01T00:00:00Z",
  };
  saveSyncMapping(dir, mapping);

  const loaded = loadSyncMapping(dir);
  assert(loaded !== null, "loaded mapping should not be null");
  assertEqual(loaded.version, 1, "loaded version");
  assertEqual(loaded.milestoneId, "M005", "loaded milestoneId");
  const taskRecord = loaded.tasks["M005/S01/T01"];
  assertEqual(taskRecord.mtTaskId, "task-abc123", "loaded mtTaskId");
  assertEqual(taskRecord.status, "in-progress", "loaded status");
  console.log("✓ save + load round-trip: data preserved correctly");
}

// Accessors — missing records return null
{
  const mapping = createEmptyMapping("M001");
  assertEqual(getSliceRecord(mapping, "M001", "S01"), null, "getSliceRecord missing");
  assertEqual(getTaskRecord(mapping, "M001", "S01", "T01"), null, "getTaskRecord missing");
  assertEqual(getMtTaskId(mapping, "M001", "S01", "T01"), null, "getMtTaskId missing");
  console.log("✓ Accessors: return null for missing records");
}

// Accessors — present records return data
{
  const mapping = createEmptyMapping("M001");
  const sliceRec = { mtSliceId: "slice-1", status: "open", lastSyncedAt: "2025-01-01T00:00:00Z" };
  setSliceRecord(mapping, "M001", "S01", sliceRec);
  const fetched = getSliceRecord(mapping, "M001", "S01");
  assertEqual(fetched.mtSliceId, "slice-1", "getSliceRecord present");

  const taskRec = { mtTaskId: "task-1", status: "todo", lastSyncedAt: "2025-01-01T00:00:00Z" };
  setTaskRecord(mapping, "M001", "S01", "T01", taskRec);
  const fetchedTask = getTaskRecord(mapping, "M001", "S01", "T01");
  assertEqual(fetchedTask.mtTaskId, "task-1", "getTaskRecord present");
  assertEqual(getMtTaskId(mapping, "M001", "S01", "T01"), "task-1", "getMtTaskId present");
  console.log("✓ Accessors: return data for present records");
}

// Mutators — set and overwrite
{
  const mapping = createEmptyMapping("M002");
  setSliceRecord(mapping, "M002", "S01", { mtSliceId: "first" });
  assertEqual(getSliceRecord(mapping, "M002", "S01").mtSliceId, "first", "initial set");
  setSliceRecord(mapping, "M002", "S01", { mtSliceId: "updated" });
  assertEqual(getSliceRecord(mapping, "M002", "S01").mtSliceId, "updated", "overwrite");
  console.log("✓ Mutators: set and overwrite correctly");
}

// Cleanup
cleanup();

console.log("\n✅ All mapping.js tests passed.");

/**
 * Unit tests for mt-cli extension cli.js
 *
 * Tests mtCliIsAvailable caching, and execFileSync success/error parsing.
 * Uses a mock "mt-cli" binary script — never depends on real mt-cli.
 */
import { writeFileSync, mkdirSync, rmSync, chmodSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import {
  mtCliIsAvailable,
  _resetMtCliCache,
  mtCliStatus,
  mtCliTasksList,
  mtCliTasksClaim,
  mtCliTasksProgress,
  mtCliTasksBlock,
  mtCliTasksUnblock,
  mtCliTasksComplete,
} from "../cli.js";

// ─── Helpers ────────────────────────────────────────────────────────────────

let _tmpDir;
function tmpPath() {
  if (!_tmpDir) {
    _tmpDir = join(tmpdir(), `mt-cli-test-${Date.now()}`);
    mkdirSync(_tmpDir, { recursive: true });
  }
  return _tmpDir;
}

function cleanup() {
  if (_tmpDir) {
    rmSync(_tmpDir, { recursive: true, force: true });
    _tmpDir = null;
  }
}

function assert(condition, message) {
  if (!condition) throw new Error(`Assertion failed: ${message}`);
}

function assertEqual(actual, expected, label) {
  if (actual !== expected) {
    throw new Error(`${label}: expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
  }
}

/**
 * Create a fake mt-cli script that echoes a fixed response.
 * On Windows we write a .cmd wrapper; on POSIX a shell script.
 */
function installFakeMtCli(response) {
  const dir = join(tmpPath(), "bin");
  mkdirSync(dir, { recursive: true });

  if (process.platform === "win32") {
    const script = join(dir, "mt-cli.cmd");
    writeFileSync(script, `@echo off\necho ${response.replace(/%/g, "%%")}\n`);
    return dir;
  } else {
    const script = join(dir, "mt-cli");
    writeFileSync(script, `#!/bin/sh\necho '${response.replace(/'/g, "'\\''")}'\n`);
    chmodSync(script, 0o755);
    return dir;
  }
}

/**
 * Create a fake mt-cli that exits with error.
 */
function installBrokenMtCli() {
  const dir = join(tmpPath(), "bin-broken");
  mkdirSync(dir, { recursive: true });

  if (process.platform === "win32") {
    const script = join(dir, "mt-cli.cmd");
    writeFileSync(script, `@echo off\necho ERROR: mt-cli not configured >&2\nexit 1\n`);
  } else {
    const script = join(dir, "mt-cli");
    writeFileSync(script, `#!/bin/sh\necho "ERROR: mt-cli not configured" >&2\nexit 1\n`);
    chmodSync(script, 0o755);
  }
  return dir;
}

